#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SIZE 5

typedef struct {
 int items[MAX_SIZE];
 int front;
 int rear;
} CircularQueue;

// Initialize queue
void initQueue(CircularQueue *q) {
 q->front = -1;
 q->rear = -1;
}

// Check if queue is empty
bool isEmpty(CircularQueue *q) {
 return (q->front == -1 && q->rear == -1);
}

// Check if queue is full (one slot kept empty)
bool isFull(CircularQueue *q) {
 return ((q->rear + 1) % MAX_SIZE == q->front);
}

// Enqueue - add element at rear
void enqueue(CircularQueue *q, int value) {
 if (isFull(q)) {
 printf("Queue is full! Cannot enqueue %d\n", value);
 return;
 }

 if (isEmpty(q)) {
 // First element
 q->front = 0;
 q->rear = 0;
 } else {
 // Circular increment using modulo
 q->rear = (q->rear + 1) % MAX_SIZE;
 }

 q->items[q->rear] = value;
 printf("Enqueued: %d\n", value);
}

// Dequeue - remove element from front
int dequeue(CircularQueue *q) {
 if (isEmpty(q)) {
 printf("Queue is empty! Cannot dequeue\n");
 return -1;
 }

 int value = q->items[q->front];
 q->items[q->front] = -1; // Optional: mark as empty

 if (q->front == q->rear) {
 // Last element - reset queue
 q->front = -1;
 q->rear = -1;
 } else {
 // Circular increment using modulo
 q->front = (q->front + 1) % MAX_SIZE;
 }

 printf("Dequeued: %d\n", value);
 return value;
}

// Peek - get front element without removing
int peek(CircularQueue *q) {
 if (isEmpty(q)) {
 printf("Queue is empty\n");
 return -1;
 }
 return q->items[q->front];
}

// Display queue contents
void display(CircularQueue *q) {
 if (isEmpty(q)) {
 printf("Queue is empty\n");
 return;
 }

 printf("Queue: ");
 int i = q->front;

 while (true) {
 printf("%d ", q->items[i]);

 if (i == q->rear) {
 break;
 }
 i = (i + 1) % MAX_SIZE;
 }
 printf("\n");
}

// Main function demonstrating circular queue
int main() {
 CircularQueue q;
 initQueue(&q);

 printf("=== Circular Queue Demo ===\n\n");

 // Enqueue elements
 enqueue(&q, 10);
 enqueue(&q, 20);
 enqueue(&q, 30);
 enqueue(&q, 40);

 display(&q);
 printf("Front element: %d\n", peek(&q));
 printf("Is full: %s\n", isFull(&q) ? "Yes" : "No");

 // Dequeue one element
 dequeue(&q);

 // Enqueue more - demonstrates wraparound
 enqueue(&q, 50);
 enqueue(&q, 60);

 display(&q);
 printf("Is full: %s\n", isFull(&q) ? "Yes" : "No");

 // Fill the queue completely
 enqueue(&q, 70);

 printf("Is full: %s\n", isFull(&q) ? "Yes" : "No");

 // Dequeue and enqueue to show continuous wraparound
 dequeue(&q);
 enqueue(&q, 80);

 display(&q);

 // Show indices
 printf("\nFront index: %d, Rear index: %d\n", q.front, q.rear);

 return 0;
}
